#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int data;
    struct Node* next;
} Node;
typedef struct {
    Node* front;
    Node* rear;
} Queue;
void initQueue(Queue* q) {
    q->front = NULL;
    q->rear = NULL;
}
void enqueue(Queue* q, int x) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = x;
    newNode->next = NULL;
    if (q->rear == NULL) {
        q->front = newNode;
        q->rear = newNode;
    } else {
        q->rear->next = newNode;
        q->rear = newNode;
    }
}
int dequeue(Queue* q) {
    if (q->front == NULL) {
        return -1;
    }
    int x = q->front->data;
    Node* temp = q->front;
    q->front = q->front->next;
    free(temp);
    if (q->front == NULL) {
        q->rear = NULL;
    }
    return x;
}
int isEmpty(Queue* q) {
    return q->front == NULL;
}
typedef struct {
    Queue q1;
    Queue q2;
} Stack;
void initStack(Stack* s) {
    initQueue(&s->q1);
    initQueue(&s->q2);
}
void push(Stack* s, int x) {
    enqueue(&s->q2, x);
    while (!isEmpty(&s->q1)) {
        enqueue(&s->q2, dequeue(&s->q1));
    }
    Queue temp = s->q1;
    s->q1 = s->q2;
    s->q2 = temp;
}
int pop(Stack* s) {
    if (isEmpty(&s->q1)) {
        return -1;
    }
    return dequeue(&s->q1);
}
int top(Stack* s) {
    if (isEmpty(&s->q1)) {
        return -1;
    }
    return s->q1.front->data;
}
int empty(Stack* s) {
    return isEmpty(&s->q1);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Stack s;
        initStack(&s);
        for (int i = 0; i < N; i++) {
            char op[10];
            scanf("%s", op);
            if (strcmp(op, "push") == 0) {
                int x;
                scanf("%d", &x);
                push(&s, x);
                printf("None\n");
            } else if (strcmp(op, "pop") == 0) {
                printf("%d\n", pop(&s));
            } else if (strcmp(op, "top") == 0) {
                printf("%d\n", top(&s));
            } else if (strcmp(op, "empty") == 0) {
                printf("%d\n", empty(&s));
            }
        }
    }
    return 0;
}

