public:
    queue<int> q1;
    queue<int> q2;
    void push(int x) {
        q2.push(x);
        while (!q1.empty()) {
            q2.push(q1.front());
            q1.pop();
        }
        swap(q1, q2);
    }
    int pop() {
        if (q1.empty()) {
            return -1;
        }
        int val = q1.front();
        q1.pop();
        return val;
