import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    public static class Stack {
        Queue<Integer> q1;
        Queue<Integer> q2;
        public Stack() {
            q1 = new LinkedList<>();
            q2 = new LinkedList<>();
        }
        public void push(int x) {
            q2.add(x);
            while (!q1.isEmpty()) {
                q2.add(q1.poll());
            }
            Queue<Integer> temp = q1;
            q1 = q2;
            q2 = temp;
        }
        public int pop() {
            if (q1.isEmpty()) {
                return -1;
            }
            return q1.poll();
        }
        public int top() {
            if (q1.isEmpty()) {
                return -1;
            }
            return q1.peek();
        }
        public boolean empty() {
            return q1.isEmpty();
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Stack s = new Stack();
            for (int i = 0; i < N; i++) {
                String op = sc.next();
                if (op.equals("push")) {
                    int x = sc.nextInt();
                    s.push(x);
                    System.out.println("None");
                } else if (op.equals("pop")) {
                    System.out.println(s.pop());
                } else if (op.equals("top")) {
                    System.out.println(s.top());
                } else if (op.equals("empty")) {
                    System.out.println(s.empty());
                }
            }
        }
    }
}

