class Stack {
    constructor() {
        this.q1 = [];
        this.q2 = [];
    }

    push(x) {
        this.q2.push(x);
        while (this.q1.length > 0) {
            this.q2.push(this.q1.shift());
        }
        [this.q1, this.q2] = [this.q2, this.q1];
    }

    pop() {
        if (this.q1.length === 0) {
            return -1;
        }
        return this.q1.shift();
    }

    top() {
        if (this.q1.length === 0) {
            return -1;
        }
        return this.q1[0];
    }

    empty() {
        return this.q1.length === 0;
    }
}

